    // }

    let openReq = indexedDB.open("test-db", 3)

    openReq.onupgradeneeded = function (e) {
        let db = e.target.result;
        if (!db.objectStoreNames.contains("courses-1")) {
            db.createObjectStore("courses-1");
        }
        if (!db.objectStoreNames.contains("courses-2")) {
            db.createObjectStore("courses-2", { autoIncrement: true });
        }
        if (!db.objectStoreNames.contains("courses-3")) {
            db.createObjectStore("courses-3", { keyPath: "title" });
        }
    }

    const courses = [
        { title: 'API', length: 40, desc: 'About API' },
        { title: 'PHP', length: 68, desc: 'About PHP' },
        { title: 'XML', length: 44, desc: 'About XML' },
    ]

    openReq.onsuccess = function (e) {
        console.log("Success!");

        db = e.target.result;
        //   const transaction = db.transaction(
        //     ["courses-1","courses-2","courses-3"],
        //     "readwrite"
        //   ); 

    }
    openReq.onerror = function (e) {
        console.log("Error");
        console.dir(e);
    }
}
